# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit

class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    private init() {}
    
    func handleUniversalLink(_ url: URL, windowScene: UIWindowScene?) {
        guard let scene = windowScene else { return }
        
        if isPasswordResetLink(url) {
            let token = extractToken(from: url)
            navigateToPasswordReset(token: token, windowScene: scene)
        }
    }
    
    private func isPasswordResetLink(_ url: URL) -> Bool {
        return url.host == "myapp.com" && url.path == "/reset-password"
    }
    
    private func extractToken(from url: URL) -> String? {
        return url.queryItems?.first { $0.name == "token" }?.value
    }
    
    private func navigateToPasswordReset(token: String?, windowScene: UIWindowScene) {
        guard let token = token else { return }
        
        let storyboard = UIStoryboard(name: "Main", bundle: nil)
        if let passwordResetVC = storyboard.instantiateViewController(withIdentifier: "PasswordResetViewController") as? PasswordResetViewController {
            passwordResetVC.resetToken = token
            
            if let window = windowScene.windows.first(where: { $0.isKeyWindow }) {
                window.rootViewController = passwordResetVC
                window.makeKeyAndVisible()
            }
        }
    }
}

extension URL {
    var queryItems: [URLQueryItem]? {
        guard let components = URLComponents(url: self, resolvingAgainstBaseURL: true),
              let queryItems = components.queryItems else {
            return nil
        }
        return queryItems
    }
